  ('immigration-1aab856d-moex-00490', 'immigration-1aab856d', 'immigration-1aab856d-moex-110-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '依最高行政法院實務見解，法規命令經訂定後，行政機關僅上網公告，而未刊登政府公報或新聞 紙，其效力為何？', '["無效", "得撤銷", "仍發生效力", "尚未發生效力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:56+00:00", "source_pdf_sha1": "ee3f88193c9a", "answer_pdf_sha1": "7385e95b2a82", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "702", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00491', 'immigration-1aab856d', 'immigration-1aab856d-moex-110-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '行政機關與人民締結行政契約，互負給付義務者，須符合一定條件之規定，下列何者不屬之？', '["契約中應約定人民給付之特定用途", "人民之給付應與國家財政收支成比例", "人民之給付有助於行政機關執行其職務", "人民之給付與行政機關之給付應相當，並具有正當合理之關聯"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:56+00:00", "source_pdf_sha1": "ee3f88193c9a", "answer_pdf_sha1": "7385e95b2a82", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "702", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00492', 'immigration-1aab856d', 'immigration-1aab856d-moex-110-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '下列何種行政行為對外發生法律效果？', '["食品衛生管理之主管機關就違反食品衛生法令之物品予以銷毀", "道路主管機關將遮掩號誌之路樹枝幹予以砍伐", "教育部公告大專院校校務統計資料", "行政機關撤銷溢發補助款後，告知相對人應於30日內返還溢領款項"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:56+00:00", "source_pdf_sha1": "ee3f88193c9a", "answer_pdf_sha1": "7385e95b2a82", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "702", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00493', 'immigration-1aab856d', 'immigration-1aab856d-moex-110-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '下列何者非屬行政罰法中裁罰性不利益處分？', '["限制某工廠之營運", "廢止某公司之營業登記", "限期改善違法行為", "公布違反義務者之姓名"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:56+00:00", "source_pdf_sha1": "ee3f88193c9a", "answer_pdf_sha1": "7385e95b2a82", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "702", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00494', 'immigration-1aab856d', 'immigration-1aab856d-moex-110-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '依行政執行法規定，下列敘述何者錯誤？', '["行政執行分署查封甲所有價值新臺幣3,000萬元之建物，甲不服該執行方法時，得聲明異議", "乙雖懷孕7個月，但身心健康良好，於行政執行程序中，仍得予以管收", "丙持刀自殺，警察為避免其發生不幸，得將其管束", "行政執行分署對執行債務人丁處以怠金前，除法律另有規定外，應先以書面限期該執行債務人 履行後，始得為之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:56+00:00", "source_pdf_sha1": "ee3f88193c9a", "answer_pdf_sha1": "7385e95b2a82", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "702", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00495', 'immigration-1aab856d', 'immigration-1aab856d-moex-110-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '關於具第三人效力之行政處分，下列敘述何者錯誤？', '["此係指除處分相對人外，同時對第三人發生法律效果", "訴訟上的鄰人訴訟即為適例", "環境影響評估審查結論影響開發案在地居民權益即屬之", "第三人因非處分相對人，尚無權要求參與行政程序"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:56+00:00", "source_pdf_sha1": "ee3f88193c9a", "answer_pdf_sha1": "7385e95b2a82", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "702", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00496', 'immigration-1aab856d', 'immigration-1aab856d-moex-110-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '依司法院大法官解釋意旨，關於行政文書送達之敘述，下列何者錯誤？', '["行政程序法所規定之寄存送達，乃一般送達、補充送達或留置送達均無法完成送達時之輔助、 替代手段", "行政程序法關於寄存送達於依法送達完畢時即生送達效力之程序規範，尚屬正當，與憲法正當 法律程序原則之要求無違", "一般送達、補充送達、留置送達或寄存送達，均以使應受送達人確實知悉應受送達文書為發生 送達效力之要件", "相關機關對行政文書送達之程序規範應如何制定，在合於憲法正當法律程序之要求下，自得裁 量決定之，而屬立法形成之範疇"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:56+00:00", "source_pdf_sha1": "ee3f88193c9a", "answer_pdf_sha1": "7385e95b2a82", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "702", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00497', 'immigration-1aab856d', 'immigration-1aab856d-moex-110-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '甲旅行社收到機場公司依機場服務費收費辦法作成之機場服務費繳款書，而機場公司受主管機關 委託而得以行使權限。若甲旅行社對於該繳款書之適法性有疑義，下列敘述何者正確？', '["甲旅行社應向主管機關提起訴願", "甲旅行社所應提起之訴願類型應為課予義務訴願", "系爭繳款書應為觀念通知，非行政處分", "逾繳款書期限後所為催繳通知，僅屬觀念通知"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:56+00:00", "source_pdf_sha1": "ee3f88193c9a", "answer_pdf_sha1": "7385e95b2a82", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "702", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 20, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00498', 'immigration-1aab856d', 'immigration-1aab856d-moex-110-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '有關行政訴訟制度，下列敘述何者正確？', '["受交通違規裁罰處分，應先經訴願程序，始得提起行政訴訟", "對於已執行而無回復原狀可能之行政處分，得提起確認該處分為違法之訴訟", "提起一般給付訴訟，應先經訴願程序，始得提起行政訴訟", "提起行政訴訟，應於訴願決定書送達後3個月之不變期間內為之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:56+00:00", "source_pdf_sha1": "ee3f88193c9a", "answer_pdf_sha1": "7385e95b2a82", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "702", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00499', 'immigration-1aab856d', 'immigration-1aab856d-moex-110-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '依司法院大法官解釋意旨，關於人民權利救濟之敘述，下列何者錯誤？', '["私立大學對於學生所為非屬退學性質之公權力措施，如侵害學生之基本權利時，學生得依法提 起相應之行政爭訟", "公立國中學生不服學校基於教育目的對其所為之公權力措施，縱屬顯然輕微之干預，仍得依法 提起相應之行政爭訟", "各級學校及其教師對學生所為之教育或管理措施享有專業判斷餘地，法院及其他行政爭訟機關 應予以較高之尊重", "公務人員不服服務機關之管理措施者，得於循申訴、再申訴程序未果後，則按相關措施之性質， 依法提起相應之行政訴訟，請求救濟"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:56+00:00", "source_pdf_sha1": "ee3f88193c9a", "answer_pdf_sha1": "7385e95b2a82", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "702", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL)
